// Small-bursty regime benchmark.
//
// The auto/work-steal scheduler (rayon-style) is tuned for large or unbalanced
// loads: `compute_k_eff` aims for ~32 elements/worker and CLAMPS TO MIN 2
// workers once total > k, so a small burst of cheap items always pays pool
// dispatch (unpark + spin + atomic coordination), and under lock contention
// `get_pool()` (try_lock) falls through to fresh `thread::scope` spawns. For
// tiny N with light per-item work that overhead can dominate the actual work.
//
// This bench sweeps tiny N across two per-item costs:
//   * CHEAP  (x + 1.0)             — dispatch overhead should dominate; serial wins
//   * HEAVY  (~256-iter fma loop)  — real work; parallel should win even at small N
//
// The CHEAP×small corner is where the current scheduler is suspected suboptimal;
// the HEAVY column is the guard rail proving a serial cutoff must NOT serialize
// genuinely parallel work. Run: `cargo bench --bench bench_small_bursty`.

use divan::black_box;
use divan::Bencher;

fn main() {
    divan::main();
}

const SIZES: &[usize] = &[8, 16, 64, 256, 1024, 4096, 16384];

#[inline]
fn heavy(seed: f64) -> f64 {
    let mut acc = seed;
    for _ in 0..256 {
        acc = acc.mul_add(1.0000001, 1.0);
    }
    acc
}

// ---- CHEAP per-item work -------------------------------------------------
#[divan::bench(args = SIZES)]
fn cheap_serial(bencher: Bencher, n: usize) {
    let mut data = vec![0.0f64; n];
    bencher.bench_local(|| {
        data.iter_mut().for_each(|x| *x = black_box(*x + 1.0));
    });
}

#[divan::bench(args = SIZES)]
fn cheap_frf_auto(bencher: Bencher, n: usize) {
    use gnosis_frf::prelude::{IntoParallelRefMutIterator, ParallelIterator};
    let mut data = vec![0.0f64; n];
    bencher.bench_local(|| {
        data.par_iter_mut().for_each(|x| *x = black_box(*x + 1.0));
    });
}

#[divan::bench(args = SIZES)]
fn cheap_rayon(bencher: Bencher, n: usize) {
    use rayon::prelude::{IntoParallelRefMutIterator, ParallelIterator};
    let mut data = vec![0.0f64; n];
    bencher.bench_local(|| {
        data.par_iter_mut().for_each(|x| *x = black_box(*x + 1.0));
    });
}

// ---- HEAVY per-item work (guard rail) ------------------------------------
#[divan::bench(args = SIZES)]
fn heavy_serial(bencher: Bencher, n: usize) {
    let mut data = vec![0.0f64; n];
    bencher.bench_local(|| {
        data.iter_mut().for_each(|x| *x = black_box(heavy(*x)));
    });
}

#[divan::bench(args = SIZES)]
fn heavy_frf_auto(bencher: Bencher, n: usize) {
    use gnosis_frf::prelude::{IntoParallelRefMutIterator, ParallelIterator};
    let mut data = vec![0.0f64; n];
    bencher.bench_local(|| {
        data.par_iter_mut().for_each(|x| *x = black_box(heavy(*x)));
    });
}

#[divan::bench(args = SIZES)]
fn heavy_rayon(bencher: Bencher, n: usize) {
    use rayon::prelude::{IntoParallelRefMutIterator, ParallelIterator};
    let mut data = vec![0.0f64; n];
    bencher.bench_local(|| {
        data.par_iter_mut().for_each(|x| *x = black_box(heavy(*x)));
    });
}
